class PageIterator implements Iterator<List<?>> {
  private String nextUrl;
  public boolean hasNext() { return nextUrl != null; }
  public List<?> next() {
    Response res = fetch(nextUrl);
    nextUrl = res.getNextUrl();
    return res.getItems();
  }
}

WITH RECURSIVE page_fetch AS (
  SELECT items, next_url FROM api_pages WHERE url = 'api/data'
  UNION ALL
  SELECT items, next_url FROM api_pages WHERE url = (SELECT next_url FROM page_fetch)
)
SELECT items FROM page_fetch;
